oldWay:
/* The classic absolute-centering hack */
.container {
  position: relative;
}
.child {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

startingCSS:
.container {
  display: grid;
  height: 280px;
  background: #1e293b;
  border-radius: 10px;
  border: 1px solid #334155;
}

.card {
  background: #a855f7;
  color: white;
  padding: 1.5rem 2rem;
  border-radius: 8px;
  text-align: center;
}

.card strong {
  display: block;
  font-size: 1rem;
  margin-bottom: 0.25rem;
}

.card p {
  margin: 0;
  opacity: 0.85;
  font-size: 0.8rem;
}

alternatives.css:
.container {
  display: flex;
  justify-content: center;
  align-items: center;
}
